from autogen import GroupChat, GroupChatManager
import hashlib

def detect_loop(messages, max_rounds=20):
    recent_msgs = messages[-10:]
    msg_hashes = [hashlib.md5(msg.content.encode()).hexdigest() for msg in recent_msgs]
    if len(set(msg_hashes)) < len(msg_hashes) * 0.3:
        return {'type': 'loop_detected', 'rounds': len(messages), 'similarity': True}
    return None

# Usage in group chat
chat_history = []
def loop_filter(message):
    chat_history.append(message)
    if len(chat_history) > max_rounds:
        result = detect_loop(chat_history)
        if result:
            return 'TERMINATE'
    return message

import re

def detect_unsafe_code(message):
    dangerous_patterns = [
        r'system\(\s*["\']shutdown["\']\s*\)',
        r'rm\s+-rf\s+',
        r'del\s+\\*\*',
        r'exec\(input\(\s*\)',
        r'__import__\(\s*["\']os["\']\s*\)'
    ]
    if '```python' in message.content:
        code_block = re.search(r'```python\n(.*?)```', message.content, re.DOTALL)
        if code_block:
            code = code_block.group(1)
            for pattern in dangerous_patterns:
                if re.search(pattern, code):
                    return {'type': 'unsafe_code', 'pattern': pattern}
    return None

def safe_reply_filter(message):
    if detect_unsafe_code(message):
        return 'Code execution blocked: unsafe patterns detected.'
    return message

from collections import Counter

def detect_false_consensus(messages):
    # Extract final conclusions from last 3 messages per agent
    conclusions = []
    for msg in messages[-9:]:
        if 'final answer' in msg.content.lower() or 'solution' in msg.content.lower():
            conclusions.append(msg.content.lower()[:100])

    if len(conclusions) >= 3:
        counts = Counter(conclusions)
        top_consensus = counts.most_common(1)[0]
        if top_consensus[1] / len(conclusions) > 0.8:
            # Verify if consensus is likely wrong (simple heuristic)
            if 'error' in top_consensus[0] or len(top_consensus[0].split()) < 10:
                return {'type': 'false_consensus', 'confidence': top_consensus[1]/len(conclusions)}
    return None

# Integrate as reply filter
def consensus_filter(message):
    result = detect_false_consensus(chat_history + [message])
    if result:
        return f'⚠️ Potential false consensus detected: {result}'
    return message

