from autogen import ConversableAgent

class DissentAgent(ConversableAgent):
    def __init__(self, *args, dissent_freq=3, **kwargs):
        super().__init__(*args, **kwargs)
        self.message_count = 0
        self.dissent_freq = dissent_freq

    def generate_reply(self, messages, sender, config):
        self.message_count += 1
        if self.message_count % self.dissent_freq == 0:
            return self.inject_dissent(messages)
        return super().generate_reply(messages, sender, config)

    def inject_dissent(self, messages):
        return "🤔 Let me challenge the consensus: What if we're missing an edge case? " \
               "Consider the opposite approach - [counter-proposal]. " \
               "Let's validate assumptions before proceeding."

# Usage
dissent_critic = DissentAgent(
    name="DissentCritic",
    system_message="Challenge consensus every 3rd response.",
    llm_config=llm_config
)

